if(window.location.hash){history.replaceState(null,'',window.location.pathname+window.location.search)}
document.getElementById('current-year').textContent=new Date().getFullYear();const animationOptions={root:null,rootMargin:'0px',threshold:0.15};const observer=new IntersectionObserver((entries,observer)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('is-visible');observer.unobserve(entry.target)}})},animationOptions);const animatedElements=document.querySelectorAll('.fade-in-section');animatedElements.forEach(el=>observer.observe(el))